/**
 * Business Information Form Page
 * 
 * Registration form for business accounts. Collects business information
 * including business name, contact person, email, phone, country of operation,
 * business category, and password. Handles starter and registered business types.
 */

import React, { useCallback, useState } from 'react';
import { createPortal } from 'react-dom';
import { useTranslation } from 'react-i18next';
import { useNavigate } from 'react-router-dom';
import { useToast } from '@/app/providers/ToastContext.jsx';
import { useTheme } from '@/app/providers/ThemeContext.jsx';
import logoDark from '@/assets/images/logo-dark.png';
import logoLight from '@/assets/images/logo-light.png';
import { authService } from '@/features/auth/services';
import { LanguageSelector, FlagIcon, PasswordRequirements, LoadingSpinner } from '@/shared/components';
import CustomSelect from '@/shared/components/CustomSelect.jsx';
import '/styles/index.css';
import { countries, industries } from '@/shared/utils/constants/countries-with-flags.js';
import { businessCategories, enhancedDueDiligenceCategories } from '@/shared/utils/businessCategories.js';
import { cleanNumberForBackend } from '@/shared/utils/format-utils.js';
import { createBusinessRegistrationSchema } from '@/shared/utils/validation/authSchemas.js';
import { mapFieldErrors } from '@/shared/utils/validation/helpers.js';
import logger from '@/shared/utils/logger.js';

const BusinessInfoForm = () => {
  const { t } = useTranslation();
  const navigate = useNavigate();
  const { success, error: showError } = useToast();
  const { effectiveTheme } = useTheme();

  const logoSrc = effectiveTheme === 'dark' ? logoDark : logoLight;
  const isAgentSignup = window.location.pathname === '/signup-agent';
  const [formData, setFormData] = useState({
    businessType: isAgentSignup ? 'agent' : '',
    businessName: '',
    contactPerson: '',
    businessEmail: '',
    countryCode: '+233',
    phoneNumber: '',
    country: '',
    category: isAgentSignup ? 'Agent' : '',
    innerCategory: '',
    password: '',
    confirmPassword: '',
  });

  const [error, setError] = useState('');
  const [formErrors, setFormErrors] = useState({});
  const [loading, setLoading] = useState(false);
  const [showPassword, setShowPassword] = useState(false);
  const [showConfirmPassword, setShowConfirmPassword] = useState(false);

  const selectedPhoneCountry = countries.find(c => c.dialCode === formData.countryCode) || countries.find(c => c.code === 'GH');
  const selectedOperationCountry = countries.find(c => c.name === formData.country);

  const clearFieldError = (name) => {
    if (formErrors[name]) {
      setFormErrors((prev) => {
        const next = { ...prev };
        delete next[name];
        if (Object.keys(next).length === 1 && next._form) {
          delete next._form;
        }
        return next;
      });
    }
  };

  const handleChange = (e) => {
    const { name, value } = e.target;

    if ((name === 'phoneNumber' || name === 'phone') && value && value.startsWith('0')) {
      setFormData({ ...formData, [name]: value.substring(1) });
      clearFieldError(name);
      return;
    }

    if (name === 'category') {
      setFormData({ ...formData, [name]: value, innerCategory: '' });
      clearFieldError(name);
      clearFieldError('innerCategory');
      return;
    }

    // Convert email to lowercase automatically
    const processedValue = name === 'email' ? value.toLowerCase() : value;

    setFormData({ ...formData, [name]: processedValue });
    clearFieldError(name);
  };

  const getInnerCategories = () => {
    if (!formData.category) { return []; }

    // Find the category in the data structure
    for (const sector in businessCategories) {
      if (businessCategories[sector][formData.category]) {
        return businessCategories[sector][formData.category];
      }
    }
    return [];
  };

  // Get available main categories
  const getMainCategories = () => {
    const mainCategories = [];
    for (const sector in businessCategories) {
      mainCategories.push(...Object.keys(businessCategories[sector]));
    }
    return mainCategories;
  };

  // Check if selected category requires enhanced due diligence
  const requiresEnhancedDueDiligence = () => {
    return enhancedDueDiligenceCategories[formData.category] === true;
  };



  const handleSubmit = useCallback(async (e) => {
    e.preventDefault();

    const schema = createBusinessRegistrationSchema(t);
    const validation = schema.safeParse(formData);

    if (!validation.success) {
      const errors = mapFieldErrors(validation.error);
      setFormErrors(errors);
      const message = Object.values(errors)[0] || t('pleaseFillAllFields', { ns: 'auth' });
      setError(message);
      showError(message);
      return;
    }

    const validated = validation.data;

    setError('');
    setFormErrors({});
    setLoading(true);

    try {
      // Prepare business registration data in the format expected by backend
      const cleanedPhone = cleanNumberForBackend(validated.phoneNumber);
      const cleanedCountryCode = cleanNumberForBackend(validated.countryCode);
      const registrationData = {
        business_name: validated.businessName,
        full_name: validated.contactPerson,
        email: validated.businessEmail,
        phone: `${cleanedCountryCode}${cleanedPhone}`,
        country: validated.country,
        industry: validated.innerCategory || validated.category,
        category: validated.category,
        innerCategory: validated.innerCategory,
        password: validated.password,
        business_type: validated.businessType,
      };

      const safeLogData = {
        business_name: registrationData.business_name,
        full_name: registrationData.full_name,
        email: registrationData.email,
        phone: registrationData.phone,
        country: registrationData.country,
        industry: registrationData.industry,
        category: registrationData.category,
        innerCategory: registrationData.innerCategory,
        business_type: registrationData.business_type,
      };
      logger.debug('Business registration data prepared', { registrationData: safeLogData });

      const response = await authService.registerBusiness(registrationData);

      const hasExplicitFailure =
        response?.success === false ||
        (response?.code !== undefined && response?.code !== '00');
      if (hasExplicitFailure) {
        const message = response?.message || t('failedToCreateBusinessAccount', { ns: 'auth' });
        throw new Error(message);
      }

      // Success - show success message
      success(t('businessAccountCreatedSuccessfully', { ns: 'auth' }));
      logger.debug('Business registration successful');

      // Redirect to login after 2 seconds
      setFormErrors({});
      setTimeout(() => {
        navigate('/login');
      }, 2000);
    } catch (err) {
      const rawMessage = err?.message || '';
      const normalizedMessage = rawMessage.toLowerCase();
      if (normalizedMessage.includes('registered successfully')) {
        setError('');
        setFormErrors({});
        success(t('businessAccountCreatedSuccessfully', { ns: 'auth' }));
        setTimeout(() => {
          navigate('/login');
        }, 2000);
        return;
      }



      // Handle network or other errors
      logger.error('Business registration error', { error: err });

      // Handle specific error cases based on error message
      let errorMessage;
      const lowerErrMessage = err.message?.toLowerCase() || '';

      if (err.message.includes('409') || lowerErrMessage.includes('already exist') || lowerErrMessage.includes('already exists')) {
        errorMessage = t('accountAlreadyExists', { ns: 'auth' });
      } else if (lowerErrMessage.includes('email') && (lowerErrMessage.includes('already') || lowerErrMessage.includes('taken'))) {
        errorMessage = t('emailAlreadyExists', { ns: 'auth' });
      } else if (lowerErrMessage.includes('phone') && (lowerErrMessage.includes('already') || lowerErrMessage.includes('taken'))) {
        errorMessage = t('phoneAlreadyExists', { ns: 'auth' });
      } else if (err.message.includes('404')) {
        errorMessage = t('apiEndpointNotFound', { ns: 'auth' });
      } else if (err.message.includes('500')) {
        errorMessage = t('serverError', { ns: 'auth' });
      } else {
        errorMessage = err.message || t('failedToCreateBusinessAccount', { ns: 'auth' });
      }

      setError(errorMessage);
      showError(errorMessage);
    } finally {
      setLoading(false);
    }
  }, [formData, t, navigate, success, showError]);

  return (
    <div className="login-container">
      <form className="login-form" onSubmit={handleSubmit} style={{ position: 'relative' }}>
        {/* Language Selector */}
        <div style={{
          position: 'absolute',
          top: '20px',
          right: '20px',
          zIndex: 10,
        }}>
          <LanguageSelector />
        </div>
        <img
          src={logoSrc}
          alt="iSmartPay Logo"
          className="login-logo"
          style={{
            transition: 'opacity var(--transition-theme)',
            opacity: 1
          }}
        />

        <h2 style={{ marginBottom: '24px' }}>{isAgentSignup ? t('agentSignUp', { ns: 'auth', defaultValue: 'Agent Sign Up' }) : t('businessSignUp', { ns: 'auth' })}</h2>
        {(error || formErrors._form) && (
          <p className="error" style={{ marginBottom: '16px' }}>
            {formErrors._form ? formErrors._form : error}
          </p>
        )}

        <div className="input-wrapper" style={{ marginBottom: '16px' }}>
          <span className="input-icon"><i className="fa-solid fa-building"></i></span>
          <CustomSelect
            name="businessType"
            value={formData.businessType}
            onChange={handleChange}
            options={[
              { value: 'starter', label: t('starterBusiness', { ns: 'auth' }) },
              { value: 'registered', label: t('registeredBusiness', { ns: 'auth' }) },
            ]}
            placeholder={t('selectBusinessType', { ns: 'auth' })}
            required
            error={formErrors.businessType}
            hasIcon={true}
          />
        </div>

        <div className="input-wrapper" style={{ marginBottom: '16px' }}>
          <span className="input-icon"><i className="fa-solid fa-briefcase"></i></span>
          <input
            type="text"
            name="businessName"
            placeholder={t('businessName', { ns: 'auth' })}
            value={formData.businessName}
            onChange={handleChange}
            required
            style={{ marginBottom: 0 }}
          />
        </div>
        {formErrors.businessName && (
          <p style={{ color: 'var(--error)', fontSize: '12px', marginTop: '-12px', marginBottom: '12px' }}>
            {formErrors.businessName}
          </p>
        )}

        <div className="input-wrapper" style={{ marginBottom: '16px' }}>
          <span className="input-icon"><i className="fa-solid fa-user"></i></span>
          <input
            type="text"
            name="contactPerson"
            placeholder={t('contactPersonFullName', { ns: 'auth' })}
            value={formData.contactPerson}
            onChange={handleChange}
            required
            style={{ marginBottom: 0 }}
          />
        </div>
        {formErrors.contactPerson && (
          <p style={{ color: 'var(--error)', fontSize: '12px', marginTop: '-12px', marginBottom: '12px' }}>
            {formErrors.contactPerson}
          </p>
        )}

        <div className="input-wrapper" style={{ marginBottom: '16px' }}>
          <span className="input-icon"><i className="fa-solid fa-envelope"></i></span>
          <input
            type="email"
            name="businessEmail"
            placeholder={t('emailAddress', { ns: 'auth' })}
            value={formData.businessEmail}
            onChange={handleChange}
            required
            style={{ marginBottom: 0 }}
          />
        </div>
        {formErrors.businessEmail && (
          <p style={{ color: 'var(--error)', fontSize: '12px', marginTop: '-12px', marginBottom: '12px' }}>
            {formErrors.businessEmail}
          </p>
        )}

        <div style={{ display: 'flex', gap: '8px', marginBottom: '16px', alignItems: 'center' }}>
          <div className="input-wrapper" style={{ width: '85px', flexShrink: 0, minWidth: '70px', marginBottom: 0 }}>
            <CustomSelect
              name="countryCode"
              value={formData.countryCode}
              onChange={handleChange}
              options={countries.map((country) => ({
                value: country.dialCode,
                label: country.dialCode,
                name: country.name,
                countryCode: country.code,
              }))}
              placeholder={t('selectCountry', { ns: 'auth' })}
              required
              error={formErrors.countryCode}
              searchable
              showCheckmark={false}
            />
          </div>
          <div className="input-wrapper" style={{ flex: 1, marginBottom: 0 }}>
            <input
              type="tel"
              name="phoneNumber"
              placeholder={t('phoneNumber', { ns: 'auth' })}
              value={formData.phoneNumber}
              onChange={handleChange}
              required
              className="input-large"
              style={{ flex: 1, marginBottom: 0 }}
            />
          </div>
        </div>

        <div className="input-wrapper" style={{ marginBottom: '16px' }}>
          <span className="input-icon"><i className="fa-solid fa-earth-africa"></i></span>
          <CustomSelect
            name="country"
            value={formData.country}
            onChange={handleChange}
            options={countries.map((country) => ({
              value: country.name,
              label: country.name,
              countryCode: country.code,
            }))}
            placeholder={t('selectCountryOfOperation', { ns: 'auth' })}
            required
            error={formErrors.country}
            hasIcon={true}
            searchable
          />
        </div>

        {isAgentSignup ? (
          <div className="input-wrapper" style={{ marginBottom: '16px' }}>
            <span className="input-icon"><i className="fa-solid fa-industry"></i></span>
            <input
              type="text"
              name="category"
              value="AGENT"
              readOnly
              style={{ marginBottom: 0, backgroundColor: 'var(--bg-tertiary)', color: 'var(--text-muted)' }}
            />
          </div>
        ) : (
          <div className="input-wrapper" style={{ marginBottom: '16px' }}>
            <span className="input-icon"><i className="fa-solid fa-industry"></i></span>
            <CustomSelect
              name="category"
              value={formData.category}
              onChange={handleChange}
              options={getMainCategories().map((category) => ({
                value: category,
                label: category
              }))}
              placeholder={t('selectBusinessCategory', { ns: 'auth' })}
              required
              error={formErrors.category}
              hasIcon={true}
            />
          </div>
        )}

        {!isAgentSignup && formData.category && (
          <div className="input-wrapper" style={{ marginBottom: '16px' }}>
            <span className="input-icon"><i className="fa-solid fa-tags"></i></span>
            <CustomSelect
              name="innerCategory"
              value={formData.innerCategory}
              onChange={handleChange}
              options={getInnerCategories().map((innerCat) => ({
                value: innerCat,
                label: innerCat
              }))}
              placeholder={t('selectSubCategory', { ns: 'auth' })}
              required
              error={formErrors.innerCategory}
              hasIcon={true}
            />
          </div>
        )}

        <div className="input-wrapper" style={{ marginBottom: '16px', position: 'relative' }}>
          <span className="input-icon"><i className="fa-solid fa-key"></i></span>
          <input
            type={showPassword ? 'text' : 'password'}
            name="password"
            placeholder={t('password', { ns: 'auth' })}
            value={formData.password}
            onChange={handleChange}
            required
            style={{ marginBottom: 0, paddingRight: '45px' }}
          />
          <button
            type="button"
            onClick={() => setShowPassword(!showPassword)}
            style={{
              position: 'absolute',
              right: '16px',
              top: '50%',
              transform: 'translateY(-50%)',
              background: 'none',
              border: 'none',
              color: '#6b7280',
              cursor: 'pointer',
              padding: '0',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              width: '20px',
              height: '20px'
            }}
            aria-label={showPassword ? t('hidePassword', { ns: 'auth' }) : t('showPassword', { ns: 'auth' })}
          >
            <i className={`fa-solid ${showPassword ? 'fa-eye-slash' : 'fa-eye'}`}></i>
          </button>
        </div>
        <PasswordRequirements password={formData.password} />
        {formErrors.password && (
          <p style={{ color: 'var(--error)', fontSize: '12px', marginTop: '8px', marginBottom: '12px' }}>
            {formErrors.password}
          </p>
        )}

        <div className="input-wrapper" style={{ marginBottom: '20px', position: 'relative' }}>
          <span className="input-icon"><i className="fa-solid fa-key"></i></span>
          <input
            type={showConfirmPassword ? 'text' : 'password'}
            name="confirmPassword"
            placeholder={t('confirmPassword', { ns: 'auth' })}
            value={formData.confirmPassword}
            onChange={handleChange}
            required
            style={{ marginBottom: 0, paddingRight: '45px' }}
          />
          <button
            type="button"
            onClick={() => setShowConfirmPassword(!showConfirmPassword)}
            style={{
              position: 'absolute',
              right: '16px',
              top: '50%',
              transform: 'translateY(-50%)',
              background: 'none',
              border: 'none',
              color: '#6b7280',
              cursor: 'pointer',
              padding: '0',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              width: '20px',
              height: '20px'
            }}
            aria-label={showConfirmPassword ? t('hidePassword', { ns: 'auth' }) : t('showPassword', { ns: 'auth' })}
          >
            <i className={`fa-solid ${showConfirmPassword ? 'fa-eye-slash' : 'fa-eye'}`}></i>
          </button>
        </div>
        {formErrors.confirmPassword && (
          <p style={{ color: 'var(--error)', fontSize: '12px', marginTop: '-12px', marginBottom: '12px' }}>
            {formErrors.confirmPassword}
          </p>
        )}

        <button
          type="submit"
          disabled={loading}
          style={{
            width: '100%',
            marginBottom: '20px'
          }}
        >
          {t('signUp', { ns: 'auth' })}
        </button>

        {/* Loading spinner popup - outside the card */}
        {loading && createPortal(
          <div style={{
            position: 'fixed',
            top: 0,
            left: 0,
            right: 0,
            bottom: 0,
            width: '100vw',
            height: '100vh',
            backgroundColor: effectiveTheme === 'dark'
              ? 'rgba(0, 0, 0, 0.85)'
              : 'rgba(0, 0, 0, 0.5)',
            backdropFilter: 'blur(4px)',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            zIndex: 99999,
            margin: 0,
            padding: 0
          }}>
            <div style={{
              backgroundColor: effectiveTheme === 'dark'
                ? '#141414'
                : 'white',
              borderRadius: '16px',
              padding: '48px',
              boxShadow: '0 20px 25px -5px rgba(0, 0, 0, 0.1), 0 10px 10px -5px rgba(0, 0, 0, 0.04)',
              display: 'flex',
              flexDirection: 'column',
              alignItems: 'center',
              justifyContent: 'center',
              minWidth: '120px',
              minHeight: '120px'
            }}>
              <LoadingSpinner size="large" />
            </div>
          </div>,
          document.body
        )}

        <hr style={{ marginBottom: '16px' }} />
        <p style={{ textAlign: 'center', marginBottom: '16px' }}>{t('alreadyHaveAccount', { ns: 'auth' })}</p>

        <button
          type="button"
          onClick={() => navigate('/login')}
          style={{ width: '100%', backgroundColor: '#23bd00' }}
        >
          {t('signInButton', { ns: 'auth' })}
        </button>
      </form>
    </div>
  );
};

export default BusinessInfoForm;
